class Solution {
public:
    int maxScore(string s) {
        int maxScore = 0;
        int zeroCount = 0;
        for (char c : s) {
            if (c == '0') {
                zeroCount++;
            }
        }
        int oneCount = s.length() - zeroCount;
        maxScore = zeroCount + oneCount;
        return maxScore;
    }
};
